// Store seen company keys from BOTH Seen Opportunities and Funding Alerts
const staticData = $getWorkflowStaticData("global");
const seenKeys = new Set();
const items = $input.all();

for (const item of items) {
  const key = item.json.Key;
  if (key && key.startsWith("company:")) {
    seenKeys.add(key);
    continue;
  }
  const companyName = item.json["Company Name"];
  if (companyName) {
    const normalizedKey = "company:" + companyName.toLowerCase().replace(/[^a-z0-9]/g, "");
    seenKeys.add(normalizedKey);
  }
}

staticData.seenCompanyKeys = Array.from(seenKeys);
console.log(`LegalTech: Stored ${seenKeys.size} seen company keys`);
return [{ json: { seenKeysLoaded: true, count: seenKeys.size } }];

// Parse The LegalTech Fund Portfolio
// Extracts companies from portfolio page with external website links
// Adds 'VC Backed': true to bypass nonprofit entity filters in pipeline
const items = $input.all();
const results = [];
const vcName = 'The LegalTech Fund';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  let html = item.json.data || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));

  // Extract portfolio company detail page links
  const portfolioLinkPattern = /href=["']\/portfolio-companies\/([^"']+)["']/gi;
  const companyMap = new Map();

  let match;
  while ((match = portfolioLinkPattern.exec(html)) !== null) {
    const slug = match[1].trim().toLowerCase();
    if (!slug || slug.length < 2) continue;

    let name = slug
      .replace(/-/g, ' ')
      .replace(/\b\w/g, c => c.toUpperCase())
      .replace(/\bAi\b/g, 'AI')
      .replace(/\.ai$/i, '.ai');

    name = name.replace(/^Ai \& /i, 'AI & ');

    if (!companyMap.has(slug)) {
      companyMap.set(slug, { name, externalUrl: '' });
    }
  }

  // Extract external company website URLs
  const externalLinkPattern = /href=["'](https?:\/\/(?!(?:www\.)?(?:legaltech\.com|linkedin|twitter|facebook|instagram|youtube|wixstatic|typeform|hubspot|tltfsummit))[^"']+)["']/gi;

  const externalUrls = [];
  while ((match = externalLinkPattern.exec(html)) !== null) {
    const url = match[1].trim();
    if (url.includes('#') || url.length < 10) continue;
    externalUrls.push(url);
  }

  // Build results
  for (const [slug, data] of companyMap) {
    const key = slug.replace(/[^a-z0-9]/g, '');
    if (seen.has(key)) continue;
    seen.add(key);

    let companyUrl = '';
    const nameParts = data.name.toLowerCase().split(/\s+/);
    for (const url of externalUrls) {
      const domain = url.match(/https?:\/\/(?:www\.)?([^.\/]+)/i)?.[1]?.toLowerCase();
      if (domain && nameParts.some(part => domain.includes(part) || part.includes(domain))) {
        companyUrl = url;
        break;
      }
    }

    results.push({
      json: {
        'Company Name': data.name,
        'VC Firm': vcName,
        'Company Description': `${data.name} - The LegalTech Fund portfolio company (legal technology)`,
        'Company URL': companyUrl,
        'Portfolio Page': `https://www.legaltech.com/portfolio-companies/${slug}`,
        'Status': 'New',
        'First Seen Date': today,
        'Source': 'VC Portfolio',
        'VC Backed': true
      }
    });
  }
}

